import ast
import os
import sys

import redis


def parse_value(value):
    try:
        return ast.literal_eval(value)
    except Exception:
        return value


def main():
    host = os.getenv("REDIS_HOST", "localhost")
    port = int(os.getenv("REDIS_PORT", "6379"))
    db = int(os.getenv("REDIS_DB", "0"))
    password = os.getenv("REDIS_PASSWORD")

    client = redis.Redis(host=host, port=port, db=db, password=password, decode_responses=True)

    script = input("Enter Lua script: ")
    numkeys = int(input("Enter number of keys: ").strip())

    keys = []
    for i in range(numkeys):
        keys.append(input(f"Key {i + 1}: "))

    numargs = int(input("Enter number of args: ").strip())
    args = []
    for i in range(numargs):
        args.append(parse_value(input(f"Arg {i + 1}: ")))

    result = client.eval(script, numkeys, *(keys + args))
    print(result)


if __name__ == "__main__":
    try:
        main()
    except redis.RedisError as e:
        print(f"Redis error: {e}", file=sys.stderr)
        sys.exit(1)
    except Exception as e:
        print(f"Error: {e}", file=sys.stderr)
        sys.exit(1)